import{_ as a,o as t,c as s,a3 as r}from"./chunks/framework.CjquFG0V.js";const l=JSON.parse('{"title":"28. Wages And Wage Increases","description":"","frontmatter":{"title":"28. Wages And Wage Increases","eba":"Allied Health Professionals 2021-2026","topics":["wages"]},"headers":[],"relativePath":"ebas/allied-health/wages/28-wages-and-wage-increases.md","filePath":"ebas/allied-health/wages/28-wages-and-wage-increases.md"}'),n={name:"ebas/allied-health/wages/28-wages-and-wage-increases.md"};function o(i,e,h,g,d,p){return t(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="_28-wages-and-wage-increases" tabindex="-1">28. Wages And Wage Increases <a class="header-anchor" href="#_28-wages-and-wage-increases" aria-label="Permalink to &quot;28. Wages And Wage Increases&quot;">​</a></h1><p><strong>28.1</strong> Weekly rates of pay prescribed by the 2020 Agreement will be increased by the amounts set out below:</p><p><strong>(a)</strong> 2% backdated to FFPPOA 1 March 2022;</p><p><strong>(b)</strong> 2% effective from FFPPOA 1 March 2023;</p><p><strong>(c)</strong> 2% effective from FFPPOA 1 March 2024; and</p><p><strong>(d)</strong> 2% effective from FFPPOA 1 March 2025.</p><p><strong>28.2</strong> The rates as amended by this Agreement are set out at <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a> of this Agreement.</p><p><strong>28.3</strong> The above rates of pay will only come into operation on the approval of this Agreement by the Commission in accordance with the Act.</p><p><strong>28.4</strong> To reduce the likelihood of undertakings required to be given to the Commission, some rates of pay have had additional minor increases applied to them above the Award wage. These are identified in <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a> of the Agreement with an asterisk symbol.</p><p><strong>28.5</strong> Translation of some Chief and Deputy Chief rates An Employee who, immediately prior to the commencement of this Agreement, held a position that subclause 28.4 of the 2020 Agreement applied to because they were classified under the 2011 Agreement at:</p><p><strong>(a)</strong> Chief Grade 2 and the Employee was at the Year 2 increment;</p><p><strong>(b)</strong> Medical Imaging Technologist Deputy Chief Grade 2 and the Employee was at the Year 2 increment;</p><p><strong>(c)</strong> Chief Grade 4; or</p><p><strong>(d)</strong> Medical Imaging Technologist Deputy Chief Grade 4; will receive the weekly rates of pay specified below: RATE RATE RATE RATE RELEVANT CHIEF CURRENT EFFECTIVE EFFECTIVE EFFECTIVE EFFECTIVE &amp; DEPUTY CHIEF CLASSIFICATIONS March 2022 March 2023 March 2024 March 2025 Chief Grade 2 $2,321.90 $2,368.30 $2,415.70 $2,184.70 $2,276.40 Year 2 * Medical Imaging Technologist $2,256.50 $2,301.70 $2,347.70 $2,168.90 $2,212.30 Deputy Chief Grade 2 Year 2 Chief Grade 4 $2,524.40 $2,574.90 $2,626.40 $2,678.90 $2,732.50</p><p>Medical Imaging Technologist $2,524.40 $2,574.90 $2,626.40 $2,678.90 $2,732.50 Deputy Chief Grade 4</p><p>*This rate is the same rate as AHP1 Grade 3 Year 4B. Patien ce in B arg ain ing Paym ent</p>',16)])])}const m=a(n,[["render",o]]);export{l as __pageData,m as default};
